/**
 * Printful firewall config generator.
 *
 * Data source: https://developers.printful.com/docs/
 *
 * Printful Private Tokens authenticate with a Bearer token in the
 * Authorization header.
 */

import { writeOutput } from "./codegen";

const DOCS_URL = "https://developers.printful.com/docs/";
const PLACEHOLDER_VALUE = "CoffeeSafeLocalCoffeeSafeLocalCoffeeSafeLocalCof";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Printful API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:printful",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const printfulFirewall = {",
    '  name: "printful",',
    '  description: "Printful API",',
    "  placeholders: {",
    `    PRINTFUL_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.printful.com",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.PRINTFUL_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];

  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Printful firewall config...");
  const ts = generateTypeScript();
  writeOutput("printful", ts, import.meta.dirname);
}
